const cache = globalThis.__productsCatalogCache ?? {
  data: null,
  fetchedAt: 0,
  refreshing: null
};

globalThis.__productsCatalogCache = cache;

async function loadProductsFromSource() {
  await new Promise((resolve) => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999 },
    { id: 2, name: 'Phone', price: 699 },
    { id: 3, name: 'Tablet', price: 499 },
    { id: 4, name: 'Headphones', price: 199 },
    { id: 5, name: 'Watch', price: 299 }
  ];
}

export async function getAllProducts() {
  if (cache.data) {
    return cache.data;
  }

  cache.data = await loadProductsFromSource();
  cache.fetchedAt = Date.now();
  return cache.data;
}

export async function refreshCatalog() {
  if (!cache.refreshing) {
    cache.refreshing = (async () => {
      const fresh = await loadProductsFromSource();
      cache.data = fresh;
      cache.fetchedAt = Date.now();
      cache.refreshing = null;
      return fresh;
    })();
  }

  return cache.refreshing;
}
EOF

